const rawCode = String($json.body?.code || "").trim();
const normalize = (value) => String(value || "").trim().toLowerCase();
const inputCode = normalize(rawCode);

const codes = {
  samuel: normalize($env.CODE_SAMUEL),
  mathilde: normalize($env.CODE_MATHILDE),
  amis_samuel: normalize($env.CODE_AMIS_SAMUEL),
  amis_mathilde: normalize($env.CODE_AMIS_MATHILDE),
};

const role = Object.entries(codes).find(([, code]) => code && code === inputCode)?.[0];
if (!role) {
  return { json: { statusCode: 401, error: "Code invalide", code: "invalid_group_code" } };
}

const apiKey = $env.AIRTABLE_PAT || $env.AIRTABLE_API_KEY;
const baseId = $env.AIRTABLE_BASE_ID;
if (!apiKey || !baseId) {
  return { json: { statusCode: 500, error: "Airtable env vars missing", code: "airtable_config_missing" } };
}

const airtable = `https://api.airtable.com/v0/${baseId}`;
const formula = `{role} = '${role.replace(/'/g, "\\'")}'`;
const searchUrl = `${airtable}/Users?maxRecords=1&filterByFormula=${encodeURIComponent(formula)}`;
const lookup = await fetch(searchUrl, { headers: { Authorization: `Bearer ${apiKey}` } });
if (!lookup.ok) {
  return { json: { statusCode: 500, error: "Airtable user lookup failed", code: "airtable_users_failed" } };
}

const data = await lookup.json();
const record = data.records?.[0];
if (!record) {
  return { json: { statusCode: 401, error: "Aucun utilisateur pour ce groupe", code: "group_user_missing" } };
}

const sessionToken = crypto.randomUUID();
const expiresAt = new Date(Date.now() + 30 * 24 * 60 * 60 * 1000).toISOString();
const patch = await fetch(`${airtable}/Users/${record.id}`, {
  method: "PATCH",
  headers: {
    Authorization: `Bearer ${apiKey}`,
    "Content-Type": "application/json"
  },
  body: JSON.stringify({
    fields: {
      session_token: sessionToken,
      session_expires_at: expiresAt
    }
  })
});

if (!patch.ok) {
  return { json: { statusCode: 500, error: "Airtable session update failed", code: "airtable_session_failed" } };
}

return {
  json: {
    session_token: sessionToken,
    user: {
      id: record.fields.id || record.id,
      name: record.fields.name || role,
      role
    }
  }
};
